const { checkoutQuote } = require('./src/checkout.js');
const { renewalPreview } = require('./src/renewal.js');

// Test 1: partner discount
const r1 = checkoutQuote([{ sku: 'INK', unitPence: 1299, qty: 3 }, { sku: 'PAPER', unitPence: 550, qty: 2 }], { accountType: 'partner' });
console.log('Test 1:', JSON.stringify(r1));
console.assert(r1.subtotalPence === 4997, 'subtotal');
console.assert(r1.discountPence === 399, 'discount 8% of 4997 = 399.76 floor 399');
console.assert(r1.handlingPence === 499, 'handling');
console.assert(r1.totalPence === 5097, 'total 4997-399+499=5097');

// Test 2: staff discount + handling override
const r2 = renewalPreview({ code: 'CARE', monthlyPence: 2500 }, 5, { accountType: 'staff', handlingOverridePence: 123 });
console.log('Test 2:', JSON.stringify(r2));
console.assert(r2.subtotalPence === 12500, 'subtotal 2500*5');
console.assert(r2.discountPence === 2500, 'discount 20% of 12500');
console.assert(r2.handlingPence === 123, 'override');
console.assert(r2.totalPence === 10123, '12500-2500+123');
console.assert(r2.months === 5, 'months');

// Test 3: no policy = standard
const r3 = checkoutQuote([{ sku: 'BOX', unitPence: 5000, qty: 1 }]);
console.log('Test 3a:', JSON.stringify(r3));
console.assert(r3.subtotalPence === 5000, 'subtotal');
console.assert(r3.discountPence === 0, 'no discount');
console.assert(r3.handlingPence === 299, 'handling >=5000');
console.assert(r3.totalPence === 5299, 'total');

// Test 4: invalid override ignored (NaN)
const r4 = renewalPreview({ monthlyPence: 3000 }, 1, { accountType: 'standard', handlingOverridePence: Number.NaN });
console.log('Test 4:', JSON.stringify(r4));
console.assert(r4.subtotalPence === 3000, 'subtotal');
console.assert(r4.discountPence === 0, 'no discount');
console.assert(r4.handlingPence === 499, 'handling <5000');
console.assert(r4.totalPence === 3499, 'total');

console.log('ALL TESTS PASSED');
"

